#pragma once

#include "crypto_core/crypto_core.hpp"

#include "test_vectors.hpp"

#include <cstdint>
#include <cstdlib>
#include <span>
#include <string_view>
#include <utility>
#include <vector>

namespace crypto_core::test_support
{

inline void require_fixture(bool condition)
{
	if (!condition)
	{
		std::exit(1);
	}
}

inline ByteBuffer bytes(std::string_view text)
{
	return ByteBuffer::copy_from(std::span<const std::uint8_t>(reinterpret_cast<const std::uint8_t *>(text.data()), text.size()));
}

inline std::vector<std::uint8_t> hex_bytes(std::string_view hex)
{
	auto decoded = decode_hex(hex);
	require_fixture(decoded.has_value());
	return std::move(decoded.value());
}

inline const std::vector<std::uint8_t> &rsa_reference_verify_public_key_der()
{
	static const auto value = hex_bytes(
	    "");
	return value;
}

inline const std::vector<std::uint8_t> &rsa_reference_pss_signature()
{
	static const auto value = hex_bytes(
	    "407FC26E5D93E6A3FA7A0D0D35F21F3F6F5D0FA903C66682F494E6188D63DC21DC59C53B9F4B7DB373F158D32EFF183044B05B8E45FA4A114782678272C734D072A189A61EFA0E68F10AB4508EAA4EACC3D80FFCDB96028375870D1C8FD8A64E360C1C693853E63743991A23AFBD86194078D585E0AC62985534AB91A6362CAD");
	return value;
}

inline const std::vector<std::uint8_t> &rsa_reference_sign_public_key_der()
{
	static const auto value = hex_bytes(
	    "");
	return value;
}

inline const std::vector<std::uint8_t> &rsa_reference_sign_private_key_der()
{
	static const auto value = hex_bytes(
	    "");
	return value;
}

inline const std::vector<std::uint8_t> &rsa_reference_oaep_sha256_ciphertext()
{
	static const auto value = hex_bytes(
	    "03628EE588D298338A0A0DA67BA4B5A2FD45391EAE44C95B5B17F1AED7E070C75D4F83B2304C1312541356D953BB6E7C9A44768F60589EFA71F8C17918815394CB877B70EDC10D6CCF27B4D19AFB7B59DBD3C583F100C0E50C9956CAEE13414C0615C38BFB3ADCCA0DC9D63A2E32D165D8DE48C0E9FD97424EDA0799FCFA067B");
	return value;
}

inline PublicKey rsa_reference_verify_key()
{
	auto key = PublicKey::import_spki_der(AsymmetricKeyAlgorithm::rsa, rsa_reference_verify_public_key_der(), KeyUsage::verify);
	require_fixture(key.has_value());
	return key.value();
}

inline PublicKey rsa_reference_sign_verify_key()
{
	auto key = PublicKey::import_spki_der(AsymmetricKeyAlgorithm::rsa, rsa_reference_sign_public_key_der(), KeyUsage::verify | KeyUsage::encrypt);
	require_fixture(key.has_value());
	return key.value();
}

inline PrivateKey rsa_reference_sign_key()
{
	auto buffer = SecureBuffer::copy_from(rsa_reference_sign_private_key_der());
	require_fixture(buffer.has_value());
	auto key = PrivateKey::import_rsa_pkcs1_der(std::move(buffer.value()), KeyUsage::sign | KeyUsage::decrypt);
	require_fixture(key.has_value());
	return std::move(key.value());
}

} // namespace crypto_core::test_support
